package com.inyaw.blog.controller;import com.inyaw.base.BaseResult;import com.inyaw.blog.bean.InyawBlogTag;import com.inyaw.blog.dao.InyawBlogTagDao;import lombok.RequiredArgsConstructor;import org.springframework.web.bind.annotation.*;import java.util.List;@RestController@RequestMapping("/tag")@RequiredArgsConstructorpublic class InyawTagController {    private final InyawBlogTagDao inyawBlogTagDao;    @PostMapping("/save")    public BaseResult<String> save(@RequestBody InyawBlogTag tag) {        inyawBlogTagDao.save(tag);        return BaseResult.success();    }    @GetMapping("/list")    public BaseResult<List<InyawBlogTag>> list() {        return BaseResult.success(inyawBlogTagDao.findAll());    }    @PostMapping("/delete")    public BaseResult<String> delete(@RequestBody InyawBlogTag tag) {        inyawBlogTagDao.delete(tag);        return BaseResult.success();    }}